const tag = `oh${Date.now().toString(36)}${randomBytes(2).toString('hex')}`;
const recoveryPath = `/tmp/rsctf-organizer-hubs-${tag}.json`;
const runStartedAt = Date.now();
const adminTarget = normalizeOrigin(process.env.ORGANIZER_HUB_ADMIN_TARGET || TARGET, 'admin target');
const execTarget = normalizeOrigin(
  process.env.ORGANIZER_HUB_EXEC_TARGET || process.env.CONTROL_TARGET || TARGET,
  'exec target',
);
const adminContainer = String(process.env.ORGANIZER_HUB_ADMIN_CONTAINER || RSCTF).trim();
const execContainer = String(process.env.ORGANIZER_HUB_EXEC_CONTAINER || RSCTF).trim();
const pgContainer = String(process.env.ORGANIZER_HUB_PG_CONTAINER || PG).trim();
const redisContainer = String(
  process.env.ORGANIZER_HUB_REDIS_CONTAINER ||
    process.env.REDIS_CONTAINER ||
    PG.replace(/-db-(\d+)$/, '-redis-$1'),
).trim();
const stackMarker = String(process.env.ADMIN_LIFECYCLE_STACK_MARKER || '').trim();
const webTargets = organizerWebTargets(
  process.env.ORGANIZER_HUB_WEB_TARGETS || process.env.WEB_TARGETS,
  adminTarget,
);
const webContainers = String(process.env.ORGANIZER_HUB_WEB_CONTAINERS || adminContainer)
  .split(',')
  .map((container) => container.trim())
  .filter(Boolean);
if (
  webContainers.length !== webTargets.length ||
  new Set(webContainers).size !== webContainers.length ||
  webContainers[webTargets.indexOf(adminTarget)] !== adminContainer
) {
  throw new Error(
    'ORGANIZER_HUB_WEB_CONTAINERS must map one-to-one with ORGANIZER_HUB_WEB_TARGETS and bind the admin target',
  );
}
const fixtureImage = String(process.env.ORGANIZER_HUB_CONTAINER_IMAGE || 'alpine:3.20').trim();
const adNetwork = String(process.env.AD_NET || 'rsctf-ad').trim();
const loadRate = positiveInteger(process.env.ORGANIZER_HUB_RATE || process.env.RATE || 1, 'load rate');
const loadVus = positiveInteger(process.env.ORGANIZER_HUB_VUS || process.env.VUS || 4, 'load VUs');
const loadDuration = String(process.env.ORGANIZER_HUB_DURATION || process.env.DURATION || '20s').trim();
