async function byocExecLifecycle(execClient) {
  if (byocMode.skipped) {
    state.reportable = false;
    state.evidence.byocExec = {
      exercised: false,
      environmentBlocked: true,
      reportable: false,
      reason: 'ORGANIZER_HUB_DIAGNOSTIC_SKIP_BYOC=1 explicitly disabled the pinned agent fixture',
    };
    return null;
  }
  let fixture;
  try {
    fixture = await provisionByocFixture();
  } catch (error) {
    if (!externalAgentArtifactBlocked(error)) throw error;
    state.evidence.byocExec = {
      exercised: false,
      environmentBlocked: true,
      reportable: false,
      reason: `pinned BYOC agent artifact unavailable: ${error.message}`,
    };
    throw error;
  }

  let invocation = 100;
  const guid = `byoc:${fixture.capability.pid}:${fixture.cid}`;
  const openAfter = execClient.frames.length;
  const opened = await execClient.invoke('Open', [guid, 'sh'], invocation++);
  const sessionId = opened.result;
  requireCondition(/^[0-9a-f]{32}$/.test(sessionId || ''), 'BYOC Open did not return a session id');
  const welcome = await execClient.waitFor(
    (frame) => decodeReceive(frame, sessionId)?.includes('connected to your BYOC service'),
    'BYOC E-stream welcome',
    { after: openAfter, timeoutMs: 10_000 },
  );
  requireCondition(!decodeReceive(welcome, sessionId).includes('not connected'), 'BYOC Open degraded to idle');

  const marker = `/tmp/${tag}.byoc-input`;
  const afterReceive = execClient.frames.length;
  await execClient.invoke('Input', [
    sessionId,
    Buffer.from(`touch ${marker}\nprintf 'organizer-byoc-exec-ok\\n'\n`).toString('base64'),
  ], invocation++);
  await waitDockerCommand('lcbyoc_svc', `test -f ${marker} && echo yes`, 'yes', 'BYOC Input side effect', 10_000);
  await execClient.waitFor(
    (frame) => decodeReceive(frame, sessionId)?.includes('organizer-byoc-exec-ok'),
    'BYOC E-stream stdout',
    { after: afterReceive, timeoutMs: 10_000 },
  );
  // v1 acknowledges resize but the BYOC transport documents it as a no-op.
  await execClient.invoke('Resize', [sessionId, 99, 31], invocation++);
  await execClient.invoke('Close', [sessionId], invocation++);
  const afterClose = `/tmp/${tag}.byoc-after-close`;
  await execClient.invoke('Input', [
    sessionId,
    Buffer.from(`touch ${afterClose}\n`).toString('base64'),
  ], invocation++);
  await sleep(250);
  dockerPathAbsent('lcbyoc_svc', afterClose, 'post-Close BYOC Input side effect');
  state.evidence.byocExec = {
    exercised: true,
    reportable: true,
    open: true,
    inputSideEffect: true,
    output: true,
    resize: 'acknowledged v1 no-op',
    closeRevokedSession: true,
    gameId: fixture.gameId,
    challengeId: fixture.cid,
    participationId: fixture.capability.pid,
  };
  return fixture;
}

async function expectScopedOpenDenied(client, target, invocationId, label) {
  let denial = null;
  let opened = null;
  try {
    opened = await client.invoke('Open', [target, 'sh'], invocationId);
  } catch (error) {
    denial = error;
  }
  if (opened?.result) {
    await client.invoke('Close', [opened.result], `${invocationId}-cleanup`).catch(() => undefined);
  }
  requireCondition(
    denial && /not unambiguously owned by this game/i.test(denial.message),
    `${label} did not return the scoped ownership denial`,
  );
}

async function scopedManagerExecLifecycle(manager, managerToken, byocFixture, fixtures) {
  const routeFixture = byocFixture
    ? {
        gameId: byocFixture.gameId,
        target: `byoc:${byocFixture.capability.pid}:${byocFixture.cid}`,
        runtimeContainer: 'lcbyoc_svc',
        backend: 'same-game BYOC',
        welcome: 'connected to your BYOC service',
      }
    : await provisionDiagnosticScopedFixture();
  const cross = await provisionCrossGameFixture(fixtures.foreignId);
  const path = scopedContainerExecPath(routeFixture.gameId);
  const crossPath = scopedContainerExecPath(cross.gameId);

  await negotiate(execTarget, path, null, 401, 'missing scoped negotiate');
  await expectWebSocketRejected(execTarget, path, null, 'missing scoped upgrade');
  await negotiate(execTarget, path, managerToken, 403, 'unassigned manager scoped negotiate');
  await expectWebSocketRejected(
    execTarget,
    path,
    managerToken,
    'unassigned ordinary user scoped upgrade',
  );
  const grant = await request(
    adminTarget,
    'POST',
    `/api/edit/games/${routeFixture.gameId}/admins/${manager.id}`,
    { token: state.primaryToken },
  );
  await expectStatus(grant, 200, 'grant exact game manager membership');
  requireCondition(
    Number(sql(
      `SELECT count(*) FROM "GameManagers" WHERE game_id=${routeFixture.gameId} ` +
        `AND user_id=${sqlLiteral(manager.id)}::uuid`,
    )) === 1,
    'exact game manager membership was not persisted once',
  );

  await negotiate(execTarget, crossPath, managerToken, 403, 'cross-game manager negotiate');
  await expectWebSocketRejected(
    execTarget,
    crossPath,
    managerToken,
    'cross-game manager scoped upgrade',
  );
  await negotiate(execTarget, crossPath, state.organizerToken, 200, 'active-game Admin scoped negotiate');
  const fenced = sql(
    `UPDATE "Games" SET deletion_pending=TRUE ` +
      `WHERE id=${cross.gameId} AND deletion_pending=FALSE RETURNING id`,
  );
  requireCondition(Number(fenced) === cross.gameId, 'failed to fence the deletion-pending scoped game');
  try {
    await negotiate(
      execTarget,
      crossPath,
      state.organizerToken,
      403,
      'deletion-pending game Admin scoped negotiate',
    );
    await expectWebSocketRejected(
      execTarget,
      crossPath,
      state.organizerToken,
      'deletion-pending game Admin scoped upgrade',
    );
  } finally {
    const restored = sql(
      `UPDATE "Games" SET deletion_pending=FALSE ` +
        `WHERE id=${cross.gameId} AND deletion_pending=TRUE RETURNING id`,
    );
    requireCondition(Number(restored) === cross.gameId, 'failed to restore the scoped deletion fence');
  }
  await negotiate(execTarget, path, state.organizerToken, 200, 'Admin scoped negotiate');
  const connection = await negotiate(
    execTarget,
    path,
    managerToken,
    200,
    'game manager scoped negotiate',
    'scoped_container_exec_negotiate',
  );
  const client = await connectHub(
    execTarget,
    path,
    managerToken,
    connection,
    'GameManagerContainerExecHub E2E',
    'scoped_container_exec_upgrade',
  );

  let invocation = 200;
  const target = routeFixture.target;
  const openAfter = client.frames.length;
  const opened = await client.invoke('Open', [target, 'sh'], invocation++);
  const sessionId = opened.result;
  requireCondition(/^[0-9a-f]{32}$/.test(sessionId || ''), 'manager Open did not return a session id');
  await client.waitFor(
    (frame) => decodeReceive(frame, sessionId)?.includes(routeFixture.welcome),
    `manager ${routeFixture.backend} welcome`,
    { after: openAfter, timeoutMs: 10_000 },
  );
  const marker = `/tmp/${tag}.manager-input`;
  const receiveAfter = client.frames.length;
  await client.invoke('Resize', [sessionId, 103, 39], invocation++);
  await client.invoke('Input', [
    sessionId,
    Buffer.from(`touch ${marker}\nprintf 'manager-scoped-exec-ok\\n'\n`).toString('base64'),
  ], invocation++);
  await waitDockerCommand(
    routeFixture.runtimeContainer,
    `test -f ${marker} && echo yes`,
    'yes',
    `manager ${routeFixture.backend} Input side effect`,
    10_000,
  );
  await client.waitFor(
    (frame) => decodeReceive(frame, sessionId)?.includes('manager-scoped-exec-ok'),
    `manager ${routeFixture.backend} stdout`,
    { after: receiveAfter, timeoutMs: 10_000 },
  );
  await expectScopedOpenDenied(
    client,
    cross.containerGuid,
    invocation++,
    'cross-game public container',
  );
  await expectScopedOpenDenied(
    client,
    fixtures.foreignId,
    invocation++,
    'arbitrary raw host container',
  );
  dockerPathAbsent(fixtures.foreignId, `/tmp/${tag}.manager-bypass`, 'scoped manager bypass marker');

  state.evidence.scopedManagerExec = {
    exercised: true,
    reportable: Boolean(byocFixture),
    gameId: routeFixture.gameId,
    allowed: `${routeFixture.backend} Open/Input/output/Resize with the session retained through load`,
    anonymous: 'negotiate=401 and upgrade rejected',
    unassignedOrdinary: 'negotiate=403 and upgrade rejected',
    crossGameManager: 'negotiate=403 and upgrade rejected',
    deletionPendingGame: 'Admin negotiate=403 and upgrade rejected',
    crossGameTarget: 'denied',
    arbitraryRawTarget: 'denied',
    membershipRevocation: 'pending after fixed-rate load',
  };
  return {
    client,
    manager,
    managerToken,
    gameId: routeFixture.gameId,
    path,
    target,
    sessionId,
    invocation,
    runtimeContainer: routeFixture.runtimeContainer,
  };
}

async function revokeScopedManagerSession(context) {
  if (!context) return;
  const { client, gameId, manager, managerToken, path, runtimeContainer, sessionId } = context;
  const frameAfter = client.frames.length;
  const closedFrame = client.waitFor(
    (frame) => frame?.type === 1 && frame.target === 'Closed' && frame.arguments?.[0] === sessionId,
    'scoped session authorization-revoked Closed event',
    { after: frameAfter, timeoutMs: 8_000 },
  );
  const socketClosed = client.waitClosed(8_000);
  const revoke = await request(
    adminTarget,
    'DELETE',
    `/api/edit/games/${gameId}/admins/${manager.id}`,
    { token: state.primaryToken },
  );
  await expectStatus(revoke, 200, 'revoke exact game manager membership');
  requireCondition(
    Number(sql(
      `SELECT count(*) FROM "GameManagers" ` +
        `WHERE game_id=${gameId} ` +
        `AND user_id=${sqlLiteral(manager.id)}::uuid`,
    )) === 0,
    'revoked game manager membership still exists',
  );

  const afterRevokePath = `/tmp/${tag}.manager-after-revoke`;
  requireCondition(!client.closed, 'manager socket closed before the post-revocation Input probe');
  client.send({
    type: 1,
    invocationId: String(context.invocation),
    target: 'Input',
    arguments: [
      sessionId,
      Buffer.from(`touch ${afterRevokePath}\n`).toString('base64'),
    ],
  });
  const outboundClosed = await closedFrame;
  requireCondition(
    /authorization revoked/i.test(String(outboundClosed.arguments?.[1] || '')),
    'scoped session Closed event did not carry the authorization-revoked reason',
  );
  await socketClosed;
  await sleep(250);
  dockerPathAbsent(runtimeContainer, afterRevokePath, 'post-revocation manager Input side effect');
  await negotiate(execTarget, path, managerToken, 403, 'revoked manager scoped negotiate');

  state.evidence.scopedManagerExec.membershipRevocation =
    'active shell emitted Closed(authorization revoked), socket closed, no Input side effect, renegotiate=403';
}

async function loadPhase(organizerToken, scopedManager) {
  if (!runLoad) {
    state.reportable = false;
    state.evidence.load = {
      skipped: true,
      reportable: false,
      reason: 'SKIP_ORGANIZER_HUB_LOAD=1',
    };
    return;
  }
  const status = runK6('organizer-hubs.js', {
    ADMIN_TARGET: adminTarget,
    EXEC_TARGET: execTarget,
    ADMIN_TOKEN: organizerToken,
    CONTAINER_GUID: state.containerGuid,
    MANAGER_TOKEN: scopedManager?.managerToken || '',
    SCOPED_GAME_ID: scopedManager?.gameId || '',
    SCOPED_TARGET: scopedManager?.target || '',
    RATE: loadRate,
    VUS: loadVus,
    DURATION: loadDuration,
    ORGANIZER_HUBS_DISPOSABLE: '1',
    CONFIRM_ORGANIZER_HUB_ADMIN_TARGET: adminTarget,
    CONFIRM_ORGANIZER_HUB_EXEC_TARGET: execTarget,
    SUMMARY_JSON: process.env.SUMMARY_JSON || '',
  });
  requireCondition(status === 0, `organizer-hub k6 load gate exited ${status}`);
  state.evidence.load = {
    skipped: false,
    reportable: state.reportable,
    ratePerTwoSeconds: loadRate,
    vus: loadVus,
    duration: loadDuration,
    scopedManagerExec: Boolean(scopedManager),
  };
}

async function revokeOrganizerSessions(organizer, adminClient, execClient) {
  const adminClosed = adminClient.waitClosed(18_000);
  const execClosed = execClient.waitClosed(8_000);
  const response = await request(adminTarget, 'PUT', `/api/admin/users/${organizer.id}`, {
    token: state.organizerToken,
    body: { role: 'User' },
  });
  await expectStatus(response, 200, 'self-demote disposable organizer');
  const demoted = userByEmail(names.organizerEmail);
  requireCondition(demoted.role === 1 && demoted.stamp !== organizer.stamp, 'self-demotion did not rotate the session stamp');
  await sleep(1_100);
  // ContainerExec revalidates before every invocation. The old token must close
  // the socket without acknowledging this Input; AdminHub revalidates on its
  // bounded 15-second lease tick.
  if (!execClient.closed) {
    execClient.send({
      type: 1,
      invocationId: 'revoked-input',
      target: 'Input',
      arguments: ['missing-session', Buffer.from('true\n').toString('base64')],
    });
  }
  await execClosed;
  await adminClosed;
  state.evidence.revocation = 'role/stamp rotation closed AdminHub and ContainerExecHub';
}

async function ensureOrganizerDemoted() {
  if (!state.users[0] || !state.organizerToken) return;
  let current;
  try {
    current = userByEmail(names.organizerEmail);
  } catch {
    return;
  }
  if (current.role !== 3) return;
  const response = await request(adminTarget, 'PUT', `/api/admin/users/${current.id}`, {
    token: state.organizerToken,
    body: { role: 'User' },
  });
  if (response.status !== 200 && response.status !== 401) throw responseError(response, 'cleanup organizer demotion');
  const after = userByEmail(names.organizerEmail);
  requireCondition(after.role !== 3, 'cleanup could not demote disposable organizer');
}

function cleanupResidualSnapshot({
  cleanupAuditRows,
  cleanupByoc,
  cleanupCross,
  cleanupScoped,
  cleanupDocker,
}) {
  const emails = [names.organizerEmail, names.ordinaryEmail, names.logProbeEmail]
    .map(sqlLiteral)
    .join(',');
  const auditIds = [...cleanupAuditRows.keys()];
  return {
    users: Number(sql(`SELECT count(*) FROM "AspNetUsers" WHERE email IN (${emails})`)),
    primaryContainer: state.containerGuid
      ? Number(sql(`SELECT count(*) FROM "Containers" WHERE id=${sqlLiteral(state.containerGuid)}::uuid`))
      : 0,
    auditRows: auditIds.length
      ? Number(sql(`SELECT count(*) FROM "Logs" WHERE id IN (${auditIds.join(',')})`))
      : 0,
    dockerFixtures: [...cleanupDocker.values()].filter((fixture) =>
      docker(['ps', '-aq', '--filter', `name=^/${fixture.name}$`]).stdout.trim()).length,
    byocGame: cleanupByoc
      ? Number(sql(`SELECT count(*) FROM "Games" WHERE id=${cleanupByoc.gameId}`))
      : 0,
    crossGame: cleanupCross
      ? Number(sql(`SELECT count(*) FROM "Games" WHERE id=${cleanupCross.gameId}`))
      : 0,
    scopedGame: cleanupScoped
      ? Number(sql(`SELECT count(*) FROM "Games" WHERE id=${cleanupScoped.gameId}`))
      : 0,
    crossContainer: cleanupCross?.containerGuid
      ? Number(sql(
        `SELECT count(*) FROM "Containers" ` +
          `WHERE id=${sqlLiteral(cleanupCross.containerGuid)}::uuid`,
      ))
      : 0,
  };
}

function requireZeroResidualSnapshot(snapshot, label) {
  for (const [resource, count] of Object.entries(snapshot)) {
    requireCondition(count === 0, `${label}: ${resource} has ${count} residual rows/resources`);
  }
}

async function cleanup() {
  if (!state.topologyAuthorized) {
    state.evidence.cleanup = 'skipped before disposable marker/topology authorization';
    return;
  }
  const errors = [];
  for (const socket of [...state.sockets]) {
    try {
      await socket.close();
    } catch (error) {
      errors.push(`socket cleanup: ${error.message}`);
    }
  }
  let cleanupByoc = state.byoc;
  let cleanupCross = state.crossGame;
  let cleanupScoped = state.scopedGame;
  try {
    const discovered = sql(`SELECT id FROM "Games" WHERE title=${sqlLiteral(state.byocTitle)} ORDER BY id`)
      .split('\n')
      .filter(Boolean)
      .map(Number);
    if (discovered.length > 1) throw new Error('disposable BYOC game title is ambiguous');
    if (!cleanupByoc && discovered.length === 1) {
      cleanupByoc = { gameId: discovered[0], cid: null, pids: [] };
    } else if (cleanupByoc && discovered.length === 1 && discovered[0] !== cleanupByoc.gameId) {
      throw new Error('disposable BYOC game identity changed');
    }
  } catch (error) {
    errors.push(`discover BYOC namespace: ${error.message}`);
  }
  try {
    const discovered = sql(`SELECT id FROM "Games" WHERE title=${sqlLiteral(state.crossGameTitle)} ORDER BY id`)
      .split('\n')
      .filter(Boolean)
      .map(Number);
    if (discovered.length > 1) throw new Error('disposable cross-game title is ambiguous');
    if (!cleanupCross && discovered.length === 1) {
      cleanupCross = { gameId: discovered[0], cid: null, containerGuid: null, runtimeId: null };
    } else if (cleanupCross && discovered.length === 1 && discovered[0] !== cleanupCross.gameId) {
      throw new Error('disposable cross-game identity changed');
    }
  } catch (error) {
    errors.push(`discover cross-game namespace: ${error.message}`);
  }
  try {
    const discovered = sql(`SELECT id FROM "Games" WHERE title=${sqlLiteral(state.scopedGameTitle)} ORDER BY id`)
      .split('\n')
      .filter(Boolean)
      .map(Number);
    if (discovered.length > 1) throw new Error('disposable scoped-game title is ambiguous');
    if (!cleanupScoped && discovered.length === 1) {
      cleanupScoped = { gameId: discovered[0], cid: null };
    } else if (cleanupScoped && discovered.length === 1 && discovered[0] !== cleanupScoped.gameId) {
      throw new Error('disposable scoped-game identity changed');
    }
  } catch (error) {
    errors.push(`discover scoped-game namespace: ${error.message}`);
  }
  if (cleanupScoped?.cid && state.containerGuid) {
    try {
      const detached = sql(
        `UPDATE "GameChallenges" SET test_container_id=NULL ` +
          `WHERE id=${cleanupScoped.cid} AND game_id=${cleanupScoped.gameId} ` +
          `AND test_container_id=${sqlLiteral(state.containerGuid)}::uuid RETURNING id`,
      );
      if (detached && Number(detached) !== cleanupScoped.cid) {
        throw new Error('detached the wrong scoped-game challenge');
      }
    } catch (error) {
      errors.push(`scoped-game container fixture: ${error.message}`);
    }
  }
  if (cleanupCross?.containerGuid) {
    try {
      const detached = sql(
        `UPDATE "GameChallenges" SET test_container_id=NULL ` +
          `WHERE id=${cleanupCross.cid} AND game_id=${cleanupCross.gameId} ` +
          `AND test_container_id=${sqlLiteral(cleanupCross.containerGuid)}::uuid RETURNING id`,
      );
      if (detached && Number(detached) !== cleanupCross.cid) {
        throw new Error('detached the wrong cross-game challenge');
      }
      const removed = sql(
        `DELETE FROM "Containers" WHERE id=${sqlLiteral(cleanupCross.containerGuid)}::uuid ` +
          `AND container_id=${sqlLiteral(cleanupCross.runtimeId)} RETURNING id`,
      );
      if (removed && removed !== cleanupCross.containerGuid) {
        throw new Error('removed the wrong cross-game Containers row');
      }
    } catch (error) {
      errors.push(`cross-game container fixture: ${error.message}`);
    }
  }
  if (cleanupByoc || cleanupCross || cleanupScoped) {
    try {
      if (cleanupByoc) {
        A.teardownFleet({
          gameId: cleanupByoc.gameId,
          cid: cleanupByoc.cid,
          pids: cleanupByoc.pids,
        });
      }
    } catch (error) {
      errors.push(`BYOC fleet: ${error.message}`);
    }
    try {
      await A.teardownNamespace(
        [cleanupByoc?.gameId, cleanupCross?.gameId, cleanupScoped?.gameId]
          .filter(Number.isSafeInteger),
      );
    } catch (error) {
      try {
        if (cleanupByoc) {
          deleteDisposableLoadGame(cleanupByoc.gameId, state.byocTitle);
        }
        if (cleanupCross) {
          deleteDisposableLoadGame(cleanupCross.gameId, state.crossGameTitle);
        }
        if (cleanupScoped) {
          deleteDisposableLoadGame(cleanupScoped.gameId, state.scopedGameTitle);
        }
        state.evidence.historyRetentionCleanup =
          'public hard-delete preserved started evidence; exact disposable graph fallback completed';
      } catch (fallbackError) {
        errors.push(
          `organizer hub game namespaces: ${error.message}; ` +
          `exact disposable fallback: ${fallbackError.message}`,
        );
      }
    }
  }
  try {
    await ensureOrganizerDemoted();
  } catch (error) {
    errors.push(`organizer demotion: ${error.message}`);
  }
  const cleanupUsers = new Map(state.users.map((user) => [user.id, user]));
  try {
    const raw = sql(
      `SELECT COALESCE(json_agg(json_build_object('id',id::text,'stamp',security_stamp,` +
        `'role',role,'name',user_name)),'[]'::json)::text FROM "AspNetUsers" ` +
        `WHERE normalized_email IN (upper(${sqlLiteral(names.organizerEmail)}),` +
        `upper(${sqlLiteral(names.ordinaryEmail)}),upper(${sqlLiteral(names.logProbeEmail)}))`,
    );
    for (const user of JSON.parse(raw || '[]')) cleanupUsers.set(user.id, user);
  } catch (error) {
    errors.push(`discover fixture users: ${error.message}`);
  }
  const cleanupOrganizer = [...cleanupUsers.values()].find((user) => user.name === names.organizer);
  if (cleanupOrganizer?.role === 3) {
    try {
      const selfToken = state.organizerToken || mintJwt(cleanupOrganizer.id, cleanupOrganizer.stamp, 3);
      const response = await request(adminTarget, 'PUT', `/api/admin/users/${cleanupOrganizer.id}`, {
        token: selfToken,
        body: { role: 'User' },
      });
      if (response.status !== 200) throw responseError(response, 'cleanup discovered organizer demotion');
    } catch (error) {
      errors.push(`discovered organizer demotion: ${error.message}`);
    }
  }
  for (const user of [...cleanupUsers.values()].reverse()) {
    try {
      const response = await request(adminTarget, 'DELETE', `/api/admin/users/${user.id}`, {
        token: state.primaryToken,
        timeoutMs: 60_000,
      });
      if (![200, 404].includes(response.status)) throw responseError(response, `delete user ${user.id}`);
    } catch (error) {
      errors.push(`user ${user.id}: ${error.message}`);
    }
  }
  if (state.containerGuid && state.containerRuntimeId) {
    try {
      const removed = sql(
        `DELETE FROM "Containers" WHERE id=${sqlLiteral(state.containerGuid)}::uuid ` +
          `AND container_id=${sqlLiteral(state.containerRuntimeId)} RETURNING id`,
      );
      if (removed && removed !== state.containerGuid) throw new Error('removed the wrong Containers row');
    } catch (error) {
      errors.push(`Containers row: ${error.message}`);
    }
  }
  const cleanupDocker = new Map(state.dockerContainers.map((fixture) => [fixture.name, fixture]));
  for (const [name, owned] of [[names.owned, true], [names.foreign, false]]) {
    const discovered = docker(['ps', '-aq', '--filter', `name=^/${name}$`]).stdout.trim();
    if (discovered && !cleanupDocker.has(name)) cleanupDocker.set(name, { id: discovered, name, owned });
  }
  for (const fixture of [...cleanupDocker.values()].reverse()) {
    try {
      const inspected = inspectContainer(fixture.id, `cleanup fixture ${fixture.name}`).record;
      requireCondition(
        inspected?.Name === `/${fixture.name}` &&
          inspected?.Config?.Labels?.[names.fixtureLabel] === tag,
        `refusing to remove Docker fixture ${fixture.id}: exact ownership changed`,
      );
      dockerMust(['rm', '-f', fixture.id], `remove Docker fixture ${fixture.name}`);
    } catch (error) {
      // Docker inspect returning absent is acceptable only when the exact name is
      // also absent (for example, --rm after daemon shutdown).
      const stillNamed = docker(['ps', '-aq', '--filter', `name=^/${fixture.name}$`]).stdout.trim();
      if (stillNamed) errors.push(`Docker fixture ${fixture.name}: ${error.message}`);
    }
  }
  const cleanupAuditRows = new Map(state.auditRows.map((row) => [Number(row.id), row]));
  if (Number.isSafeInteger(state.logFloor) && state.primaryName) {
    try {
      const raw = sql(
        `SELECT COALESCE(json_agg(json_build_object('id',id,'logger',logger,'name',user_name,` +
          `'message',message,'level',level,'status',status) ORDER BY id),'[]'::json)::text ` +
          `FROM "Logs" WHERE id>${state.logFloor} AND logger='AdminController' AND (` +
          `(user_name=${sqlLiteral(state.primaryName)} AND message='Successfully added 2 users') OR ` +
          `(user_name=${sqlLiteral(names.organizer)} AND message='Successfully added 1 users'))`,
      );
      const discovered = JSON.parse(raw || '[]');
      const primaryRows = discovered.filter((row) => row.name === state.primaryName);
      const organizerRows = discovered.filter((row) => row.name === names.organizer);
      const known = new Set(state.auditRows.map((row) => Number(row.id)));
      if (primaryRows.length > 1 && primaryRows.some((row) => !known.has(Number(row.id)))) {
        throw new Error('primary Admin audit discovery is ambiguous; refusing to delete concurrent rows');
      }
      if (organizerRows.length > 1 && organizerRows.some((row) => !known.has(Number(row.id)))) {
        throw new Error('disposable organizer emitted an unexpected duplicate semantic audit row');
      }
      for (const row of discovered) cleanupAuditRows.set(Number(row.id), row);
    } catch (error) {
      errors.push(`discover fixture audit rows: ${error.message}`);
    }
  }
  for (const row of cleanupAuditRows.values()) {
    try {
      const removed = sql(
        `DELETE FROM "Logs" WHERE id=${Number(row.id)} AND logger=${sqlLiteral(row.logger)} ` +
          `AND user_name=${sqlLiteral(row.name)} AND message=${sqlLiteral(row.message)} RETURNING id`,
      );
      if (removed && Number(removed) !== Number(row.id)) throw new Error('removed the wrong audit row');
    } catch (error) {
      errors.push(`audit row ${row.id}: ${error.message}`);
    }
  }

  try {
    const emails = [names.organizerEmail, names.ordinaryEmail, names.logProbeEmail]
      .map(sqlLiteral)
      .join(',');
    requireCondition(
      Number(sql(`SELECT count(*) FROM "AspNetUsers" WHERE email IN (${emails})`)) === 0,
      'fixture users remain',
    );
    if (state.containerGuid) {
      requireCondition(
        Number(sql(`SELECT count(*) FROM "Containers" WHERE id=${sqlLiteral(state.containerGuid)}::uuid`)) === 0,
        'fixture Containers row remains',
      );
    }
    if (cleanupAuditRows.size) {
      const ids = [...cleanupAuditRows.keys()].join(',');
      requireCondition(Number(sql(`SELECT count(*) FROM "Logs" WHERE id IN (${ids})`)) === 0, 'fixture audit rows remain');
    }
    for (const fixture of cleanupDocker.values()) {
      requireCondition(
        !docker(['ps', '-aq', '--filter', `name=^/${fixture.name}$`]).stdout.trim(),
        `Docker fixture ${fixture.name} remains`,
      );
    }
    if (cleanupByoc) {
      requireCondition(
        Number(sql(`SELECT count(*) FROM "Games" WHERE id=${cleanupByoc.gameId}`)) === 0,
        'BYOC fixture game remains',
      );
    }
    if (cleanupCross) {
      requireCondition(
        Number(sql(`SELECT count(*) FROM "Games" WHERE id=${cleanupCross.gameId}`)) === 0,
        'cross-game fixture remains',
      );
      if (cleanupCross.containerGuid) {
        requireCondition(
          Number(sql(
            `SELECT count(*) FROM "Containers" ` +
              `WHERE id=${sqlLiteral(cleanupCross.containerGuid)}::uuid`,
          )) === 0,
          'cross-game Containers row remains',
        );
      }
    }
    if (cleanupScoped) {
      requireCondition(
        Number(sql(`SELECT count(*) FROM "Games" WHERE id=${cleanupScoped.gameId}`)) === 0,
        'scoped fixture game remains',
      );
    }
  } catch (error) {
    errors.push(`residual audit: ${error.message}`);
  }
  try {
    const delayMs = Number(process.env.ORGANIZER_HUB_CLEANUP_STABILITY_MS || 2_000);
    requireCondition(
      Number.isSafeInteger(delayMs) && delayMs >= 1_000 && delayMs <= 10_000,
      'ORGANIZER_HUB_CLEANUP_STABILITY_MS must be an integer from 1000 through 10000',
    );
    await sleep(delayMs);
    const first = cleanupResidualSnapshot({
      cleanupAuditRows,
      cleanupByoc,
      cleanupCross,
      cleanupScoped,
      cleanupDocker,
    });
    requireZeroResidualSnapshot(first, 'first delayed residual snapshot');
    await sleep(delayMs);
    const second = cleanupResidualSnapshot({
      cleanupAuditRows,
      cleanupByoc,
      cleanupCross,
      cleanupScoped,
      cleanupDocker,
    });
    requireZeroResidualSnapshot(second, 'second delayed residual snapshot');
    requireCondition(
      JSON.stringify(first) === JSON.stringify(second),
      'residual snapshots changed between delayed reads',
    );
    state.evidence.cleanupResidualSnapshots = { delayMs, first, second };
  } catch (error) {
    errors.push(`delayed residual snapshots: ${error.message}`);
  }
  if (errors.length) throw new Error(errors.join('; '));
}

async function main() {
  const topology = assertSafeTopology();
  state.evidence.runtimeIdentity = {
    before: inspectUniformServerRuntimeIdentity(serverContainers),
    after: null,
  };
  lock = await acquireExclusiveProcessLock(loadOrchestrationLockPath, {
    label: 'organizer-hub lifecycle',
    metadata: { tag, composeProject: topology.composeProject },
  });
  databaseLock = await acquireAdminLifecycleDatabaseLock();
  state.topologyAuthorized = true;
  state.evidence.topology = {
    composeProject: topology.composeProject,
    adminContainer,
    execContainer,
    pgContainer,
    redisContainer,
    webTargets,
    webContainers,
    tunnelNetwork: NET,
    adNetwork,
  };
  saveRecovery();
  await healthPreflight(topology);
  await inverseTopologyPreflight();
  saveRecovery();
  checkInterrupted();

  const primary = resolvePrimaryAdmin();
  state.primaryToken = primary.token;
  state.primaryName = primary.name;
  state.logFloor = maxLogId();
  const profile = await request(adminTarget, 'GET', '/api/account/profile', { token: primary.token });
  await expectStatus(profile, 200, 'primary Admin preflight');
  requireCondition(profile.json?.role === 'Admin', 'primary token did not resolve to Admin');

  const { organizer, ordinary, ordinaryToken } = await createIdentities(primary);
  await authorizationMatrix(ordinaryToken, state.organizerToken);
  saveRecovery();
  checkInterrupted();

  const adminConnection = await negotiate(
    adminTarget,
    '/hub/admin',
    state.organizerToken,
    200,
    'AdminHub E2E negotiate',
    'admin_negotiate',
  );
  const adminClient = await connectHub(
    adminTarget,
    '/hub/admin',
    state.organizerToken,
    adminConnection,
    'AdminHub E2E',
    'admin_upgrade',
  );
  await receivedLogLifecycle(organizer, adminClient);

  const fixtures = createDockerFixtures(topology.scope);
  const execConnection = await negotiate(
    execTarget,
    '/hub/containerExec',
    state.organizerToken,
    200,
    'ContainerExecHub E2E negotiate',
    'container_exec_negotiate',
  );
  const execClient = await connectHub(
    execTarget,
    '/hub/containerExec',
    state.organizerToken,
    execConnection,
    'ContainerExecHub E2E',
    'container_exec_upgrade',
  );
  await containerExecLifecycle(execClient, fixtures);
  saveRecovery();
  const byocFixture = await byocExecLifecycle(execClient);
  saveRecovery();
  const scopedManager = await scopedManagerExecLifecycle(
    ordinary,
    ordinaryToken,
    byocFixture,
    fixtures,
  );
  const runtimeCoverageCount = assertPrivilegedHubRuntimeCoverage(coveredSurfaces);
  state.evidence.privilegedHubRuntimeCoverage = {
    count: runtimeCoverageCount,
    surfaces: [...coveredSurfaces].sort(),
  };
  saveRecovery();
  checkInterrupted();

  await loadPhase(state.organizerToken, scopedManager);
  saveRecovery();
  await revokeScopedManagerSession(scopedManager);
  saveRecovery();
  await revokeOrganizerSessions(organizer, adminClient, execClient);
  saveRecovery();
}

let primaryError = null;
try {
  await main();
} catch (error) {
  primaryError = error;
  state.scenarioFailure = String(error?.stack || error?.message || error);
  state.failure = { phase: 'scenario', message: String(error?.stack || error?.message || error) };
  saveRecovery();
}
let cleanupError = null;
try {
  await cleanup();
} catch (error) {
  cleanupError = error;
  state.cleanupFailure = String(error?.stack || error?.message || error);
  state.failure = {
    phase: primaryError ? 'scenario-and-cleanup' : 'cleanup',
    message: String(error?.stack || error?.message || error),
  };
  saveRecovery();
}
let verificationError = null;
if (state.topologyAuthorized) {
  try {
    const startingRuntimeIdentity = state.evidence.runtimeIdentity.before;
    state.evidence.runtimeIdentity.after = inspectUnchangedServerRuntimeIdentity(
      startingRuntimeIdentity,
      serverContainers,
    );
    saveRecovery();
    const fatalLogsByContainer = Object.fromEntries(
      originalServerRuntimeLogTargets(startingRuntimeIdentity).map(({ name, containerId }) => [
        name,
        {
          containerId,
          fatalLineCount: countContainerFatalLogs(containerId, runStartedAt),
        },
      ]),
    );
    state.evidence.fatalLogAudit = fatalLogsByContainer;
    const fatalLogs = Object.values(fatalLogsByContainer)
      .reduce((sum, value) => sum + value.fatalLineCount, 0);
    requireCondition(fatalLogs === 0, `runtime log audit found ${fatalLogs} panic/fatal records`);
    state.evidence.runtimeIdentity.after = inspectUnchangedServerRuntimeIdentity(
      startingRuntimeIdentity,
      serverContainers,
    );
  } catch (error) {
    verificationError = error;
    state.verificationFailure = String(error?.stack || error?.message || error);
    saveRecovery();
  }
}
const leaseErrors = [];
for (const [label, lease] of [['database', databaseLock], ['process', lock]]) {
  if (!lease) continue;
  try {
    await lease.release();
  } catch (error) {
    const wrapped = new Error(`${label} organizer-hub lease release failed: ${error.message}`);
    leaseErrors.push(wrapped);
    state.leaseFailures.push(String(wrapped.stack || wrapped.message));
    saveRecovery();
  }
}

state.cleanupVerified = state.topologyAuthorized && cleanupError === null;
state.completed = primaryError === null && cleanupError === null &&
  verificationError === null && leaseErrors.length === 0;
state.completedAt = Date.now();
saveRecovery();

if (primaryError || cleanupError || verificationError || leaseErrors.length) {
  const failures = [];
  if (primaryError) failures.push(`scenario: ${primaryError.stack || primaryError.message}`);
  if (cleanupError) failures.push(`cleanup: ${cleanupError.stack || cleanupError.message}`);
  if (verificationError) failures.push(`verification: ${verificationError.stack || verificationError.message}`);
  failures.push(...leaseErrors.map((error) => `lease release: ${error.stack || error.message}`));
  throw new Error(failures.join('\n'));
}

console.log('\norganizer hub lifecycle passed');
console.log(`  AdminHub: negotiate + WebSocket auth + actual ReceivedLog (${state.evidence.receivedLog.msg})`);
console.log('  ContainerExecHub: Open + Input + Resize + Close on exact RSCTF-owned fixture');
console.log('  arbitrary raw container: rejected into an inert session; no command side effect');
console.log(`  session revocation: ${state.evidence.revocation}`);
console.log(`  fixed-rate load: ${JSON.stringify(state.evidence.load)}`);
console.log(`  BYOC exec: ${state.evidence.byocExec.exercised ? 'Open + Input/output + Resize + Close' : `environment-blocked — ${state.evidence.byocExec.reason}`}`);
console.log(`  scoped manager exec: ${state.evidence.scopedManagerExec.exercised ? 'same-game allowed; cross-game/raw denied; membership revoke closed socket' : state.evidence.scopedManagerExec.reason}`);
console.log('  cleanup: exact users, audit rows, Containers rows, game namespaces, and Docker fixtures absent');
console.log(`  recovery/audit manifest: ${recoveryPath}`);
if (!shouldRetainLifecycleManifest({
  completed: state.completed,
  cleanupVerified: state.cleanupVerified,
  keep: process.env.KEEP_ORGANIZER_HUB_MANIFEST,
})) removeRecovery(recoveryPath);
